class Solution {
    public long[] unmarkedSumArray(int[] nums, int[][] queries) {
        int n = nums.length, m = queries.length;
        long[] answer = new long[m];
        boolean[] marked = new boolean[n];
        long sum = 0;
        for (int num : nums) sum += num;

        for (int i = 0; i < m; i++) {
            int index = queries[i][0], k = queries[i][1];
            if (!marked[index]) {
                marked[index] = true;
                sum -= nums[index];
            }
            int[] unmarked = new int[n];
            int count = 0;
            for (int j = 0; j < n; j++) {
                if (!marked[j]) {
                    unmarked[count++] = j;
                }
            }
            Arrays.sort(unmarked, 0, count, (a, b) -> nums[a] == nums[b] ? a - b : nums[a] - nums[b]);
            for (int j = 0; j < Math.min(k, count); j++) {
                marked[unmarked[j]] = true;
                sum -= nums[unmarked[j]];
            }
            answer[i] = sum;
        }
        return answer;
    }
}
